// /frontend/src/components/WeatherOverlay.jsx
import React, { useEffect, useMemo, useRef } from "react";

// --- Desktop MP4s ---
import fogday from "./overlays/desktop/fogday.mp4";
import fognight from "./overlays/desktop/fognight.mp4";
import pcday from "./overlays/desktop/pcday.mp4";
import pcnight from "./overlays/desktop/pcnight.mp4";
import clearday from "./overlays/desktop/clearday.mp4";
import clearnight from "./overlays/desktop/clearnight.mp4";
import cloudyday from "./overlays/desktop/cloudyday.mp4";
import cloudynight from "./overlays/desktop/cloudynight.mp4";
import rainday from "./overlays/desktop/rainday.mp4";
import rainnight from "./overlays/desktop/rainnight.mp4";
import thunderstormday from "./overlays/desktop/thunderstormday.mp4";
import thunderstormnight from "./overlays/desktop/thunderstormnight.mp4";
import snowday from "./overlays/desktop/snowday.mp4";
import snownight from "./overlays/desktop/snownight.mp4";

// --- Mobile MP4s ---
import fogdaymobile from "./overlays/mobile/fogdaymobile.mp4";
import fognightmobile from "./overlays/mobile/fognightmobile.mp4";
import pcdaymobile from "./overlays/mobile/pcdaymobile.mp4";
import pcnightmobile from "./overlays/mobile/pcnightmobile.mp4";
import cleardaymobile from "./overlays/mobile/cleardaymobile.mp4";
import clearnightmobile from "./overlays/mobile/clearnightmobile.mp4";
import cloudydaymobile from "./overlays/mobile/cloudydaymobile.mp4";
import cloudynightmobile from "./overlays/mobile/cloudynightmobile.mp4";
import raindaymobile from "./overlays/mobile/raindaymobile.mp4";
import rainnightmobile from "./overlays/mobile/rainnightmobile.mp4";
import thunderstormdaymobile from "./overlays/mobile/thunderstormdaymobile.mp4";
import thunderstormnightmobile from "./overlays/mobile/thunderstormnightmobile.mp4";
import snowdaymobile from "./overlays/mobile/snowdaymobile.mp4";
import snownightmobile from "./overlays/mobile/snownightmobile.mp4";

// Map for desktop videos
const OVERLAY_MAP_DESKTOP = {
  fogday,
  fognight,
  pcday,
  pcnight,
  clearday,
  clearnight,
  cloudyday,
  cloudynight,
  rainday,
  rainnight,
  thunderstormday,
  thunderstormnight,
  snowday,
  snownight,
};

// Map for mobile videos
const OVERLAY_MAP_MOBILE = {
  fogday: fogdaymobile,
  fognight: fognightmobile,
  pcday: pcdaymobile,
  pcnight: pcnightmobile,
  clearday: cleardaymobile,
  clearnight: clearnightmobile,
  cloudyday: cloudydaymobile,
  cloudynight: cloudynightmobile,
  rainday: raindaymobile,
  rainnight: rainnightmobile,
  thunderstormday: thunderstormdaymobile,
  thunderstormnight: thunderstormnightmobile,
  snowday: snowdaymobile,
  snownight: snownightmobile,
};

// Map weather condition to overlay key
function mapConditionToKey(condition, isDay) {
  if (!condition || typeof condition !== "string") return isDay ? "clearday" : "clearnight";
  const text = condition.toLowerCase();

  if (text.includes("cloud") && text.includes("part")) return isDay ? "pcday" : "pcnight";
  if (text.includes("cloud")) return isDay ? "cloudyday" : "cloudynight";
  if (text.includes("fog") || text.includes("mist") || text.includes("haze"))
    return isDay ? "fogday" : "fognight";
  if (text.includes("rain") || text.includes("drizzle"))
    return isDay ? "rainday" : "rainnight";
  if (text.includes("thunder")) return isDay ? "thunderstormday" : "thunderstormnight";
  if (text.includes("snow") || text.includes("sleet")) return isDay ? "snowday" : "snownight";

  return isDay ? "clearday" : "clearnight";
}

export default function WeatherOverlay({ condition, isDay }) {
  const videoRef = useRef(null);
  const isMobile = window.innerWidth <= 768;

  const videoSrc = useMemo(() => {
    const key = mapConditionToKey(condition, isDay);
    return isMobile ? OVERLAY_MAP_MOBILE[key] : OVERLAY_MAP_DESKTOP[key];
  }, [condition, isDay, isMobile]);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.load();
    }
  }, [videoSrc]);

  return (
    <video
      ref={videoRef}
      src={videoSrc}
      autoPlay
      loop
      muted
      playsInline
      className="fixed top-0 left-0 w-full h-full object-cover -z-10"
    />
  );
}
